def cleanup_tensor_dimensions(tensor, target_axes):
    def get_shape(nested_list):
        if not isinstance(nested_list, list):
            return []
        shape = [len(nested_list)]
        if nested_list:
            inner_shape = get_shape(nested_list[0])
            shape.extend(inner_shape)
        return shape

    def squeeze_axis(nested_list, axis, current_depth=0):
        if current_depth == axis:
            if not isinstance(nested_list, list) or len(nested_list) != 1:
                raise ValueError(f"cannot select an axis to squeeze out which has size not equal to one")
            return nested_list[0]

        if not isinstance(nested_list, list):
            return nested_list

        return [squeeze_axis(item, axis, current_depth + 1) for item in nested_list]

    def squeeze_all_singleton_dims(nested_list):
        if not isinstance(nested_list, list):
            return nested_list

        if len(nested_list) == 1:
            return squeeze_all_singleton_dims(nested_list[0])

        return [squeeze_all_singleton_dims(item) for item in nested_list]

    if target_axes is None:
        return squeeze_all_singleton_dims(tensor)

    if isinstance(target_axes, int):
        target_axes = [target_axes]

    result = tensor
    # Sort axes in descending order to avoid index shifting issues
    for axis in sorted(target_axes, reverse=True):
        result = squeeze_axis(result, axis)

    return result

