def solve_eigenvalue_problem(a):
    # Convert input to numpy array
    matrix = np.array(a)

    # Compute eigenvalues and eigenvectors
    eigenvals, eigenvecs = np.linalg.eig(matrix)

    # Sort by real part of eigenvalues in descending order
    sorted_indices = np.argsort(eigenvals.real)[::-1]
    sorted_eigenvals = eigenvals[sorted_indices]
    sorted_eigenvecs = eigenvecs[:, sorted_indices]

    # Convert eigenvalues to list (handling complex numbers)
    eigenvalues_list = []
    for val in sorted_eigenvals:
        if np.isreal(val) and abs(val.imag) < 1e-10:
            eigenvalues_list.append(float(val.real))
        else:
            eigenvalues_list.append(complex(val))

    # Convert eigenvectors to nested list
    eigenvectors_list = []
    for i in range(sorted_eigenvecs.shape[1]):
        eigenvec = []
        for j in range(sorted_eigenvecs.shape[0]):
            val = sorted_eigenvecs[j, i]
            if np.isreal(val) and abs(val.imag) < 1e-10:
